import{_ as i,o as l,c as t,ae as n}from"./chunks/framework.CB71nIlf.js";const o="/cogniand-manual.github.io/assets/%E5%AE%9E%E9%AA%8C%E8%AF%A6%E6%83%85.cx7xqmX0.png",r="/cogniand-manual.github.io/assets/%E6%95%B0%E6%8D%AE%E5%AF%BC%E5%87%BA.cFfrvSsD.png",e="/cogniand-manual.github.io/assets/%E5%AE%9E%E9%AA%8C%E8%AF%84%E5%88%86.CAtPZKd7.png",s="/cogniand-manual.github.io/assets/%E8%A2%AB%E8%AF%95%E5%AE%9E%E9%AA%8C%E5%90%8E%E5%8F%B0.CnrRXtM2.png",u="/cogniand-manual.github.io/assets/%E4%B8%BB%E8%AF%95%E5%88%9B%E5%BB%BA%E5%AE%9E%E9%AA%8C.vGIEOKz2.png",A=JSON.parse('{"title":"实验相关问题","description":"","frontmatter":{},"headers":[],"relativePath":"1-FAQ/2-experiment.md","filePath":"1-FAQ/2-experiment.md"}'),h={name:"1-FAQ/2-experiment.md"};function p(g,a,m,c,d,q){return l(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="实验相关问题" tabindex="-1">实验相关问题 <a class="header-anchor" href="#实验相关问题" aria-label="Permalink to &quot;实验相关问题&quot;">​</a></h1><h2 id="被试相关" tabindex="-1">被试相关 <a class="header-anchor" href="#被试相关" aria-label="Permalink to &quot;被试相关&quot;">​</a></h2><h3 id="q7-如何参与实验" tabindex="-1">Q7: 如何参与实验？ <a class="header-anchor" href="#q7-如何参与实验" aria-label="Permalink to &quot;Q7: 如何参与实验？&quot;">​</a></h3><p><strong>A</strong>: 在实验详情即可参与实验。 <img src="'+o+'" alt="注册页面"></p><p>详细步骤：<a href="./../3-subject-manual/3-experiments.html">被试手册 - 参与实验</a></p><h3 id="q8-实验数据如何获取" tabindex="-1">Q8: 实验数据如何获取？ <a class="header-anchor" href="#q8-实验数据如何获取" aria-label="Permalink to &quot;Q8: 实验数据如何获取？&quot;">​</a></h3><p><strong>A</strong>: 实验完成后，在实验结果详情页面点击导出按钮获取实验数据。 <img src="'+r+'" alt="数据导出"></p><p><strong>支持的文件格式</strong>：</p><ul><li>CSV</li><li>JSON</li><li>TXT</li></ul><h3 id="q12-实验评分有什么作用" tabindex="-1">Q12: 实验评分有什么作用？ <a class="header-anchor" href="#q12-实验评分有什么作用" aria-label="Permalink to &quot;Q12: 实验评分有什么作用？&quot;">​</a></h3><p><strong>A</strong>: 被试对实验的评分可以帮助其他被试了解实验质量，也可以帮助主试改进实验设计。</p><p><strong>评分范围</strong>：1-5星</p><ul><li>5星：非常满意</li><li>4星：满意</li><li>3星：一般</li><li>2星：不满意</li><li>1星：非常不满意</li></ul><p><strong>评分内容</strong>：</p><ul><li>实验设计合理性</li><li>实验说明清晰度</li><li>实验时长准确性</li><li>整体体验 <img src="'+e+'" alt="注册页面"></li></ul><h3 id="q13-如何收藏实验" tabindex="-1">Q13: 如何收藏实验？ <a class="header-anchor" href="#q13-如何收藏实验" aria-label="Permalink to &quot;Q13: 如何收藏实验？&quot;">​</a></h3><p><strong>A</strong>:</p><p>点击实验详情页的&quot;收藏&quot;按钮可收藏实验。</p><h3 id="q14-实验报名需要审核吗" tabindex="-1">Q14: 实验报名需要审核吗？ <a class="header-anchor" href="#q14-实验报名需要审核吗" aria-label="Permalink to &quot;Q14: 实验报名需要审核吗？&quot;">​</a></h3><p><strong>A</strong>: 根据实验设置，部分实验需要主试审核，部分实验可自动通过。</p><p><strong>审核流程</strong>：</p><ol><li>提交报名申请</li><li>主试查看申请</li><li>主试审核（通过/拒绝）</li><li>被试收到通知</li><li>开始实验</li></ol><p><img src="'+s+'" alt="注册页面"></p><h2 id="主试相关" tabindex="-1">主试相关 <a class="header-anchor" href="#主试相关" aria-label="Permalink to &quot;主试相关&quot;">​</a></h2><h3 id="q9-如何创建实验" tabindex="-1">Q9: 如何创建实验？ <a class="header-anchor" href="#q9-如何创建实验" aria-label="Permalink to &quot;Q9: 如何创建实验？&quot;">​</a></h3><p><strong>A</strong>: ❌ <strong>当前实验创建功能尚未完全实现</strong>。</p><p>前端有完整的实验创建界面，但后端缺少对应的API实现，暂时无法保存和发布新实验。</p><p><strong>前端界面包含</strong>：</p><ul><li>实验基本信息设置</li><li>实验范式配置</li><li>招募条件设置</li><li>知情同意书编辑</li></ul><p><img src="'+u+'" alt="注册页面"> 详细说明：<a href="/cogniand-manual.github.io/2-experimenter-manual/3-experiment-management/3-2-create-experiment.html">主试手册 - 创建实验</a></p><h3 id="q10-实验数据如何导出" tabindex="-1">Q10: 实验数据如何导出？ <a class="header-anchor" href="#q10-实验数据如何导出" aria-label="Permalink to &quot;Q10: 实验数据如何导出？&quot;">​</a></h3><p><strong>计划支持的导出格式</strong>：</p><ul><li>CSV（Excel可打开）</li><li>JSON（程序处理）</li><li>SPSS格式</li><li>自定义格式</li></ul><p>详细说明：<a href="/cogniand-manual.github.io/2-experimenter-manual/6-data-management.html">主试手册 - 数据管理</a></p><h3 id="q11-如何邀请被试参与实验" tabindex="-1">Q11: 如何邀请被试参与实验？ <a class="header-anchor" href="#q11-如何邀请被试参与实验" aria-label="Permalink to &quot;Q11: 如何邀请被试参与实验？&quot;">​</a></h3><p><strong>A</strong>: 登录主试账号，进入&quot;邀请管理&quot;页面，点击&quot;生成邀请链接&quot;，复制链接发送给被试，或使用&quot;发送邮件&quot;功能批量邀请。</p><p><strong>邀请方式</strong>：</p><ol><li><strong>邮件邀请</strong>：输入被试邮箱，系统自动发送邀请邮件</li><li><strong>链接分享</strong>：复制邀请链接，通过社交媒体分享</li><li><strong>二维码分享</strong>：生成二维码，打印或展示</li></ol><p>详细步骤：<a href="/cogniand-manual.github.io/2-experimenter-manual/5-invite-system/">主试手册 - 邀请系统</a></p><h2 id="实验范式" tabindex="-1">实验范式 <a class="header-anchor" href="#实验范式" aria-label="Permalink to &quot;实验范式&quot;">​</a></h2><h3 id="q15-平台支持哪些实验范式" tabindex="-1">Q15: 平台支持哪些实验范式？ <a class="header-anchor" href="#q15-平台支持哪些实验范式" aria-label="Permalink to &quot;Q15: 平台支持哪些实验范式？&quot;">​</a></h3><p><strong>A</strong>: CogniAND平台支持多种心理学实验范式，涵盖：</p><p><strong>认知实验范式</strong>：</p><ul><li>Stroop色词干扰任务</li><li>N-back工作记忆任务</li><li>Eriksen侧抑制任务</li><li>任务切换</li><li>信号检测任务</li><li>等</li></ul><p><strong>情绪实验范式</strong>：</p><ul><li>眼神读心测试（RMET）</li><li>共情测试</li><li>疼痛共情</li><li>敬畏情绪</li><li>等</li></ul><p><strong>社会认知实验范式</strong>：</p><ul><li>Asch从众实验</li><li>道德判断</li><li>社会排斥</li><li>文化归因</li><li>等</li></ul><p><strong>决策与博弈实验范式</strong>：</p><ul><li>独裁者博弈</li><li>信任博弈</li><li>最后通牒博弈</li><li>囚徒困境</li><li>公共物品博弈</li><li>等</li></ul><p>完整列表请查看：<a href="/cogniand-manual.github.io/4-platform-info/1-about.html">平台信息 - 实验范式库</a></p><h3 id="q16-如何使用实验模板" tabindex="-1">Q16: 如何使用实验模板？ <a class="header-anchor" href="#q16-如何使用实验模板" aria-label="Permalink to &quot;Q16: 如何使用实验模板？&quot;">​</a></h3><p><strong>A</strong>: 登录主试账号，访问&quot;模板库&quot;页面，浏览可用的实验模板，选择合适的模板，点击&quot;使用模板&quot;进行定制。</p><p><strong>模板库功能</strong>：</p><ul><li>浏览所有可用模板</li><li>按类别筛选模板</li><li>预览模板效果</li><li>基于模板创建实验</li></ul><p>详细说明：<a href="/cogniand-manual.github.io/2-experimenter-manual/4-template-library.html">主试手册 - 模板库使用</a></p><p><strong>还有其他实验相关问题？</strong> 请查看：</p><ul><li><a href="/cogniand-manual.github.io/2-experimenter-manual/">主试手册</a></li><li><a href="/cogniand-manual.github.io/3-subject-manual/">被试手册</a></li><li><a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a></li></ul>',58)])])}const E=i(h,[["render",p]]);export{A as __pageData,E as default};
